module.exports = async function (data) {
  const { transform_payload, languages = [], hotel_translate = [] } = data;

  const fromId = transform_payload?.from_translation_id;
  const toId = transform_payload?.to_translation_id;

  if (!fromId || !toId) {
    return {
      isTranslatable: false,
      data: [],
      error: "Missing from_translation_id or to_translation_id",
    };
  }

  const hotel = hotel_translate.find((h) => h);

  if (!hotel) {
    return {
      isTranslatable: false,
      data: [],
      error: "No hotel_translate record found",
    };
  }

  const toLanguage = languages.find((lang) => lang?.id === toId);

  if (!toLanguage) {
    return {
      isTranslatable: false,
      data: [],
      error: "Target language not found",
    };
  }

  // Find source multiple translation
  const sourceMultiple = hotel.translations_multiple?.find(
    (t) => t?.translations_id?.id === fromId
  );

  if (!sourceMultiple) {
    return {
      isTranslatable: false,
      data: [],
      error: "Source multiple translation not found",
    };
  }

  // Check if target translation already exists
  const existingMultipleTarget = hotel.translations_multiple?.find(
    (t) => t?.translations_id?.id === toId
  );

  const keysToTranslate = ["name", "description"];

  const result = keysToTranslate
    .filter((key) => sourceMultiple[key]) // only keys that exist
    .map((key) => ({
      hotel_translate_id: hotel.id,
      field: key,
      data_to_translate: sourceMultiple[key],
      from_language: sourceMultiple.translations_id,
      to_language: toLanguage,
      hasToTranslateData: !!existingMultipleTarget,
      existingTranslation: existingMultipleTarget
        ? existingMultipleTarget
        : null,
    }));

  return {
    isTranslatable: result.length > 0,
    data: result,
  };
};

