module.exports = async function(data) {
  const d = new Date();
  d.setDate(d.getDate() + 5);
  const target = d.toISOString().split('T')[0];

  let isSendNotification = false;

  const endDateStr = data.read_data?.[0]?.end_date;

  if (endDateStr) {
    const endDate = (new Date(endDateStr)).getTime();
    const targetDate = (new Date(target)).getTime();

    if (endDate <= targetDate) {
      isSendNotification = true;
    }

    return { target_date: target, isSendNotification, endDate, targetDate, read_data: data.read_data ,endDateStr};
  }

  return { target_date: target, isSendNotification, read_data: data.read_data ,endDateStr};
};

module.exports = async function(data) {
  const payload = data.$trigger.payload;
  const existing = data.read_item;

  // Merge: payload fields take precedence over existing DB values
  const start_date = 'start_date' in payload ? payload.start_date : existing.start_date;
  const end_date = 'end_date' in payload ? payload.end_date : existing.end_date;

  let publication_status;

  if (!start_date && !end_date) {
    publication_status = 'never published';
  } else if (!start_date && end_date) {
    publication_status = 'never published';
  } else if (start_date && !end_date) {
    publication_status = 'always published';
  } else {
    publication_status = 'published period';
  }

  return { publication_status };
}

module.exports = async function(data) {
