  return { item_key: key };
};

module.exports = async function(data) {
  const allPartners = data['read_all_partners'];
  const allHotels = data['read_all_hotels'];

  const totalPartners = Array.isArray(allPartners) ? allPartners.length : 0;

  const toAll = [];
  const toSelected = [];
  const toNull = [];

  if (Array.isArray(allHotels)) {
    for (var i = 0; i < allHotels.length; i++) {
      var hotel = allHotels[i];

      var uniquePartnerIds = new Set(
        Array.isArray(hotel.partner)
          ? hotel.partner.map(function(p) { return p.partner_id; })
          : []
      );
      var selectedCount = uniquePartnerIds.size;

      if (selectedCount === 0) {
        if (hotel.partner_type !== null) {
          toNull.push({ id: hotel.id, name: hotel.hotel_name, current: hotel.partner_type });
        }
      } else if (selectedCount >= totalPartners) {
        if (hotel.partner_type !== 'all') {
          toAll.push({ id: hotel.id, name: hotel.hotel_name, current: hotel.partner_type });
        }
      } else {
        if (hotel.partner_type !== 'selected') {
          toSelected.push({ id: hotel.id, name: hotel.hotel_name, current: hotel.partner_type });
        }
      }
    }
  }

  return {
    to_all: toAll.map(function(h) { return h.id; }),
    to_selected: toSelected.map(function(h) { return h.id; }),
    to_null: toNull.map(function(h) { return h.id; }),
    has_to_all: toAll.length > 0,
    has_to_selected: toSelected.length > 0,
    has_to_null: toNull.length > 0,
    to_all_log: toAll.length > 0 ? toAll.map(function(h) { return h.name + ' (' + h.id + ') [was: ' + h.current + '] → all'; }).join('\n') : 'None',
    to_selected_log: toSelected.length > 0 ? toSelected.map(function(h) { return h.name + ' (' + h.id + ') [was: ' + h.current + '] → selected'; }).join('\n') : 'None',
    to_null_log: toNull.length > 0 ? toNull.map(function(h) { return h.name + ' (' + h.id + ') [was: ' + h.current + '] → null'; }).join('\n') : 'None'
  };
};

module.exports = async function(data) {
  const allPartners = data['read_all_partners'];
  const filters = data['read_filters'];

  if (!Array.isArray(allPartners) || !Array.isArray(filters)) {
    return { records: [], count: 0 };
  }

  const allPartnerIds = allPartners.map(function(p) { return p.id; });
  const records = [];

  for (var i = 0; i < filters.length; i++) {
    var filter = filters[i];
    var existingIds = new Set(
      (filter.selected_partners || []).map(function(sp) { return sp.partner_id; })
    );

    for (var j = 0; j < allPartnerIds.length; j++) {
      if (!existingIds.has(allPartnerIds[j])) {
        records.push({
          partner_filter_id: filter.id,
          partner_id: allPartnerIds[j]
        });
      }
    }
  }

  return { records: records, count: records.length };
};

