module.exports = async function(data) {
  const hotel = data.hotel;
  const roomCategories = data.room_categories;
  const priceDates = data.price_dates;
  const occupancies = data.occupancies;
  const roomPrices = data.room_prices;

  // Maps
  const roomCategoryMap = Object.fromEntries(
    roomCategories.map(rc => [rc.id, rc])
  );

  const priceDateMap = Object.fromEntries(
    priceDates.map(pd => [pd.id, pd])
  );

  const occupancyMap = Object.fromEntries(
    occupancies.map(o => [o.id, o])
  );

  // Step 1: Filter eligible
  const eligibleRoomPrices = roomPrices.filter(rp => {
    const roomCategory = roomCategoryMap[rp.room_category_id];
    const priceDate = priceDateMap[rp.price_date_id];
    const occupancy = occupancyMap[rp.occupancy_id];

    return (
      (roomCategory?.from_price === true ||
        priceDate?.from_price === true ||
        occupancy?.from_price === true) &&
      rp.sell_price !== null &&
      !isNaN(Number(rp.sell_price))
    );
  });

  // Step 2: Get lowest
  const lowestRoomPrice = eligibleRoomPrices.reduce((lowest, current) => {
    if (!lowest) return current;

    return Number(current.sell_price) < Number(lowest.sell_price)
      ? current
      : lowest;
  }, null);

  return {
    eligible_room_prices: eligibleRoomPrices,
    lowest_room_price: lowestRoomPrice,
    from_price_update: [
      {
        id: data.transform_payload.hotel_id,
        from_price: lowestRoomPrice ? lowestRoomPrice.id : null
      }
    ]
  };
};

